def sequence_closure_plans(
    plans: list[DimensionPlan],
    annual_budget: int,
) -> list[tuple[str, int, str]]:
    """
    Prioritise dimension plans by gap size descending, then by ROI
    (expected level gain per $1000 invested). Returns ordered list of
    (dimension, budget_allocated, rationale).
    """
    def roi(plan: DimensionPlan) -> float:
        if not plan.total_investment:
            return 0.0
        total_gain = sum(a.expected_level_gain for a in plan.actions)
        return total_gain / (plan.total_investment / 1000)

    # Sort by gap first (larger gap = higher priority), then by ROI
    sorted_plans = sorted(
        plans, key=lambda p: (p.gap, roi(p)), reverse=True
    )

    results = []
    remaining = annual_budget
    for plan in sorted_plans:
        alloc = min(plan.total_investment, remaining)
        rationale = (
            f"gap={plan.gap}, roi={roi(plan):.3f} levels per $1k"
        )
        results.append((plan.dimension, alloc, rationale))
        remaining -= alloc
        if remaining <= 0:
            break
    return results
